BaseMapManager = class("BaseMapManager")

function BaseMapManager:ctor(mapConfig, processId)
    self.processId = processId
    self.mapConfig = mapConfig
    self.hp = mapConfig.hp
    self.extraHp = 0
    self.pathList = {}
    self.gridList = BaseGridList.new()
    self.propsTrigger = PropsTrigger.new(self)

    if not isClient then
        self.roundConfig = RoundConfig:getRoundGroupByCheckPointId(mapConfig.id)
        local roomConfig = RoomConfig:getRoomConfigById(processId)
        self.pathIds = roomConfig[mapConfig.id].pathIds
    end
    BaseGridListManager:addGridList(self.gridList, self.processId)
end

function BaseMapManager:addPath(pathId)
    self.pathList[pathId] = PathManager.new(pathId, self.processId)
    self.gridList:initPathGrid(pathId)
end

function BaseMapManager:getPath(pathId)
    return self.pathList[pathId]
end

function BaseMapManager:getPathByUserId(userId)
    for _, path in pairs(self.pathList) do
        for _, pUserId in pairs(path.protectUserId) do
            if tostring(pUserId) == tostring(userId) then
                return path
            end
        end
    end
end

function BaseMapManager:onDestroy()
    LuaEntityManager:clearEntity(self)
    for _, path in pairs(self.pathList) do
        path:onDestroy()
    end
    self.pathList = {}
end